const input = $input.first().json;
const evoBody = input.content?.body || {};
const data = evoBody.data || {};
const message = data.message || {};
const key = data.key || {};

const conversationText =
  message.conversation ||
  message.extendedTextMessage?.text ||
  message.imageMessage?.caption ||
  message.videoMessage?.caption ||
  '';

// Phone resolution: senderPn (sender real) tem prioridade sobre remoteJid (@lid)
const senderPn = key.senderPn || '';
const rawJid = key.remoteJid || '';
const sourceJid = senderPn || rawJid;
const phone = sourceJid.split('@')[0];

const isGroup = rawJid.endsWith('@g.us');
const isLid = rawJid.endsWith('@lid');

const normalizedBody = {
  event: evoBody.event,
  instance: evoBody.instance,
  text: {
    message: conversationText,
  },
  senderName: data.pushName || '',
  phone: phone,
  fromMe: key.fromMe || false,
  audio: message.audioMessage || null,
  image: message.imageMessage || null,
  video: message.videoMessage || null,
  document: message.documentMessage || null,
  sticker: message.stickerMessage || null,
  isGroup: isGroup,
  isLid: isLid,
  remoteJid: rawJid,
  senderPn: senderPn,
  messageId: key.id || '',
  messageType: data.messageType || '',
  timestamp: data.messageTimestamp || 0,
  data: data,
  raw: evoBody,
  chatwootMessageId: data.chatwootMessageId,
  chatwootInboxId: data.chatwootInboxId,
  chatwootConversationId: data.chatwootConversationId,
  server_url: evoBody.server_url,
  apikey: evoBody.apikey,
};

return [{
  json: {
    body: normalizedBody,
  },
}];

const persona = $('Set Persona').first().json;
const norm = $('Normalizacao').first().json;

const searchResult = $('Airtable - Search User in Leads Autobot').all();
const lead = searchResult.length > 0 ? searchResult[0].json : {};

const cliente = persona.cliente_ativo === 'TM' ? {
  nome: persona.cliente_nome_tm,
  perguntas: persona.perguntas_tm,
  email: persona.email_tm
} : {
  nome: persona.cliente_nome_tj,
  perguntas: persona.perguntas_tj,
  email: persona.email_tj
};

const historico = lead.concat_Messages || '(primeira mensagem desta conversa)';

const respostasDadas = [1,2,3,4,5,6]
  .map(n => 'resposta' + n + ': ' + (lead['resposta' + n] || '(ainda nao respondida)'))
  .join('\n');

const systemPrompt = (persona.system_prompt || '')
  .split('[[agente_nome]]').join(persona.agente_nome || '')
  .split('[[cliente_nome]]').join(cliente.nome || '')
  .split('[[link_calendly]]').join(persona.link_calendly || '')
  .split('[[perguntas]]').join(cliente.perguntas || '');

const prompt = systemPrompt + '\n\n'
  + '=== DADOS DO LEAD ===\n'
  + 'Nome: ' + (lead.Name || norm.user_name || 'desconhecido') + '\n'
  + 'Email: ' + (lead.Email || '(nao informado)') + '\n'
  + 'Telefone: ' + norm.user_phone + '\n\n'
  + '=== RESPOSTAS JA RECOLHIDAS ===\n'
  + respostasDadas + '\n\n'
  + '=== HISTORICO DA CONVERSA ===\n'
  + historico + '\n\n'
  + '=== MENSAGEM NOVA DO LEAD ===\n'
  + ($('messageAgregated').first().json.messageUser || norm.message_object_textmessage) + '\n\n'
  + 'Responda agora, APENAS com o objeto JSON no formato obrigatorio.';

return [{
  json: {
    prompt: prompt,
    timeout: 120,
    user_phone: norm.user_phone,
    user_name: norm.user_name,
    message_nova: ((Array.isArray($('messageAgregated').first().json.messageUser)?$('messageAgregated').first().json.messageUser.join('\n'):$('messageAgregated').first().json.messageUser) || norm.message_object_textmessage),
    airtable_record_id: lead['Airtable ID'] || lead.id || '',
    cliente_ativo: persona.cliente_ativo,
    email_atendimento: cliente.email
  }
}];

const bridgeOutput = $input.first().json;
const txt = bridgeOutput.output || '';

const loginFail = txt.includes('Not logged in') || txt.includes('Please run /login');
const tooShort = txt.trim().length <= 10;

if (txt && !loginFail && !tooShort) {
  return [{ json: {
    output: txt,
    elapsed_s: bridgeOutput.elapsed_s || 0,
    fallback: false,
    prompt: $('Build Prompt').first().json.prompt
  } }];
}

return [{ json: {
  output: '',
  elapsed_s: 0,
  fallback: true,
  prompt: $('Build Prompt').first().json.prompt
} }];

const raw = $('Fallback Router SDR').first().json.output || '';
const clean = raw.replace(/```json/g, '').replace(/```/g, '').trim();

let p;
try {
  p = JSON.parse(clean);
} catch (e) {
  p = { resposta: 'Desculpe, pode repetir por favor?', idioma: 'pt', acao: 'nenhuma', campo_resposta: null, valor_resposta: null, qualificacao_completa: false, _parse_failed: true };
}

const bp = $('Build Prompt').first().json;
return [{ json: {
  resposta: p.resposta || '',
  idioma: p.idioma || 'pt',
  acao: p.acao || 'nenhuma',
  campo_resposta: p.campo_resposta || null,
  valor_resposta: p.valor_resposta || null,
  qualificacao_completa: p.qualificacao_completa || false,
  user_phone: bp.user_phone,
  user_name: bp.user_name,
  message_nova: bp.message_nova,
  airtable_record_id: bp.airtable_record_id,
  cliente_ativo: bp.cliente_ativo,
  motor: 'bridge'
} }];

const j = $json;
const out = { airtable_record_id: j.airtable_record_id };
if (j.campo_resposta && j.valor_resposta) {
  out[j.campo_resposta] = j.valor_resposta;
}
return [{ json: out }];

const ctx = $('Set Contexto Resposta').first().json;
const merged = $input.first().json;

let resposta = ctx.resposta || '';

const link = merged.scheduling_link || '';
if (link && (ctx.acao === 'reagendar' || ctx.acao === 'agendar')) {
  resposta = (resposta ? resposta + '\n\n' : '') + 'Escolha o melhor horario aqui: ' + link;
}

let linkMeet = '';
try {
  const s = $('Airtable - Search User in Leads Autobot1').first().json;
  linkMeet = s.linkMeet || (s.fields && s.fields.linkMeet) || '';
} catch (e) {
  linkMeet = '';
}

if (ctx.qualificacao_completa === true && linkMeet) {
  resposta = (resposta ? resposta + '\n\n' : '')
    + 'Como lembrete, a sua reuniao ja esta agendada. Aqui esta o link novamente: ' + linkMeet;
}

return [{ json: {
  resposta: resposta,
  user_phone: ctx.user_phone,
  user_name: ctx.user_name,
  message_nova: ctx.message_nova,
  airtable_record_id: ctx.airtable_record_id
} }];

